#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
typedef long long ll;
inline ll read()
{
	ll res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=110,Mod=1e9+7;
template<typename T> inline void DN(T&x){x>=Mod?x-=Mod:0;} 
template<typename T> inline void UP(T&x){x<0?x+=Mod:0;} 
int n;ll nn,mm,All,a[N],b[N],p;__int128 dp[110][2][2];
inline ll S0(ll x){return ((__int128)x*(x+1)/2)%Mod;}
inline ll Count(ll nn,ll mm)
{
	mm=min(mm,nn);
//	printf("cnm %lld %lld\n",nn,mm);
	return (S0(mm+1)+(nn-mm)%Mod*((mm+1)%Mod))%Mod;
}
int main()
{
//	printf("%lld\n",Count(3,6));
	int T=read();p=read(); Begin:
	
	nn=read();mm=min(nn,read());
	All=Count(nn,mm);
//	printf("%lld\n",All);
	memset(a,0,sizeof(a));
	memset(b,0,sizeof(b));
	n=0;while(mm){b[++n]=mm%p;mm/=p;}
	n=0;while(nn){a[++n]=nn%p;nn/=p;}
	memset(dp,0,sizeof(dp));
	rep(0,1,i)rep(0,1,j)dp[0][i][j]=1;
	rep(1,n,i)
	{
		dp[i][0][0]=dp[i-1][0][0]*S0(p);
		dp[i][0][1]=dp[i-1][0][1]*(p-b[i])+dp[i-1][0][0]*(S0(p)-S0(p-b[i])+Mod);
		dp[i][1][0]=dp[i-1][1][0]*(a[i]+1)+dp[i-1][0][0]*S0(a[i]);
		dp[i][1][1]=dp[i-1][1][1]*(a[i]>=b[i])+dp[i-1][1][0]*min(b[i],a[i]+1)+dp[i-1][0][1]*max(0ll,a[i]-b[i])+dp[i-1][0][0]*Count(a[i]-1,b[i]-1);
		rep(0,1,x)rep(0,1,y)dp[i][x][y]%=Mod;
	}
//	printf("%lld\n",ll(dp[2][1][1]));
//	printf("%d %d %d %d\n",int(dp[1][0][0]),int(dp[1][0][1]),int(dp[1][1][0]),int(dp[1][1][1]));
	UP(All-=dp[n][1][1]);printf("%lld\n",All);
	
	if(--T)goto Begin;return 0;
}
